sp_portal.css:
/* IDP Kiro — AWS Carbon Design System Theme
 * Carbon Design System tokens mapped to ServiceNow Service Portal
 * https://carbondesignsystem.com/guidelines/color/tokens/
 */

:root {
  /* Carbon color tokens */
  --cds-interactive-01: #0f62fe;
  --cds-interactive-02: #393939;
  --cds-interactive-03: #0f62fe;
  --cds-interactive-04: #0f62fe;
  --cds-ui-background: #ffffff;
  --cds-ui-01: #f4f4f4;
  --cds-ui-02: #ffffff;
  --cds-ui-03: #e0e0e0;
  --cds-ui-04: #8d8d8d;
  --cds-ui-05: #161616;
  --cds-text-01: #161616;
  --cds-text-02: #525252;
  --cds-text-03: #a8a8a8;
  --cds-text-04: #ffffff;
  --cds-text-05: #6f6f6f;
  --cds-link-01: #0f62fe;
  --cds-link-02: #0043ce;
  --cds-icon-01: #161616;
  --cds-icon-02: #525252;
  --cds-icon-03: #ffffff;
  --cds-field-01: #f4f4f4;
  --cds-field-02: #ffffff;
  --cds-inverse-01: #ffffff;
  --cds-inverse-02: #393939;
  --cds-support-01: #da1e28;
  --cds-support-02: #198038;
  --cds-support-03: #f1c21b;
  --cds-support-04: #0043ce;
  --cds-overlay-01: rgba(22, 22, 22, 0.5);
  --cds-focus: #0f62fe;
  --cds-hover-primary: #0353e9;
  --cds-hover-primary-text: #0043ce;
  --cds-hover-secondary: #4c4c4c;
  --cds-hover-ui: #e5e5e5;
  --cds-active-primary: #002d9c;
  --cds-active-secondary: #6f6f6f;
  --cds-active-ui: #c6c6c6;
  --cds-selected-ui: #e0e0e0;
  --cds-highlight: #d0e2ff;
  --cds-skeleton-01: #e5e5e5;
  --cds-skeleton-02: #c6c6c6;

  /* Carbon spacing scale */
  --cds-spacing-01: 0.125rem;
  --cds-spacing-02: 0.25rem;
  --cds-spacing-03: 0.5rem;
  --cds-spacing-04: 0.75rem;
  --cds-spacing-05: 1rem;
  --cds-spacing-06: 1.5rem;
  --cds-spacing-07: 2rem;
  --cds-spacing-08: 2.5rem;
  --cds-spacing-09: 3rem;
  --cds-spacing-10: 4rem;
  --cds-spacing-11: 5rem;
  --cds-spacing-12: 6rem;
  --cds-spacing-13: 10rem;

  /* Carbon typography */
  --cds-productive-heading-01-font-size: 0.875rem;
  --cds-productive-heading-01-font-weight: 600;
  --cds-productive-heading-02-font-size: 1rem;
  --cds-productive-heading-02-font-weight: 600;
  --cds-productive-heading-03-font-size: 1.25rem;
  --cds-productive-heading-03-font-weight: 400;
  --cds-productive-heading-04-font-size: 1.75rem;
  --cds-productive-heading-04-font-weight: 400;
  --cds-body-short-01-font-size: 0.875rem;
  --cds-body-short-01-line-height: 1.28572;
  --cds-body-long-01-font-size: 0.875rem;
  --cds-body-long-01-line-height: 1.42857;
  --cds-label-01-font-size: 0.75rem;
  --cds-label-01-font-weight: 400;
}

/* IBM Plex Sans font stack */
body, .navbar, .sp-widget, .panel {
  font-family: 'IBM Plex Sans', 'Helvetica Neue', Arial, sans-serif;
  color: var(--cds-text-01);
  background-color: var(--cds-ui-background);
}

/* Top navigation bar */
.navbar-default {
  background-color: var(--cds-ui-05);
  border: none;
  height: 48px;
  min-height: 48px;
}

.navbar-default .navbar-brand {
  color: var(--cds-text-04) !important;
  font-size: var(--cds-productive-heading-02-font-size);
  font-weight: var(--cds-productive-heading-02-font-weight);
  padding: 14px 16px;
  height: 48px;
}

.navbar-default .navbar-nav > li > a {
  color: var(--cds-text-04) !important;
  font-size: var(--cds-body-short-01-font-size);
  padding: 14px 16px;
  height: 48px;
}

.navbar-default .navbar-nav > li > a:hover {
  background-color: var(--cds-hover-secondary);
  color: var(--cds-text-04) !important;
}

/* Carbon button styles */
.btn-primary, .btn-idp-primary {
  background-color: var(--cds-interactive-01);
  border-color: var(--cds-interactive-01);
  color: var(--cds-text-04);
  font-size: var(--cds-body-short-01-font-size);
  font-weight: 400;
  padding: 0.875rem 1rem;
  border-radius: 0;
  min-height: 3rem;
  transition: background-color 70ms cubic-bezier(0, 0, 0.38, 0.9);
}

.btn-primary:hover, .btn-idp-primary:hover {
  background-color: var(--cds-hover-primary);
  border-color: var(--cds-hover-primary);
}

.btn-secondary, .btn-idp-secondary {
  background-color: var(--cds-interactive-02);
  border-color: var(--cds-interactive-02);
  color: var(--cds-text-04);
  font-size: var(--cds-body-short-01-font-size);
  padding: 0.875rem 1rem;
  border-radius: 0;
  min-height: 3rem;
}

/* Carbon tile */
.bx--tile {
  background-color: var(--cds-ui-01);
  padding: var(--cds-spacing-05);
  border: 1px solid var(--cds-ui-03);
  min-height: 4rem;
  transition: background-color 70ms cubic-bezier(0, 0, 0.38, 0.9);
}

.bx--tile:hover {
  background-color: var(--cds-hover-ui);
  cursor: pointer;
}

.bx--tile--clickable:focus {
  outline: 2px solid var(--cds-focus);
  outline-offset: -2px;
}

/* Carbon side navigation */
.bx--side-nav {
  position: fixed;
  top: 48px;
  bottom: 0;
  left: 0;
  width: 256px;
  background-color: var(--cds-ui-01);
  border-right: 1px solid var(--cds-ui-03);
  overflow-y: auto;
  transition: width 110ms cubic-bezier(0.2, 0, 1, 0.9);
  z-index: 1000;
}

.bx--side-nav--collapsed {
  width: 48px;
}

.bx--side-nav__item {
  list-style: none;
  padding: 0;
}

.bx--side-nav__link {
  display: flex;
  align-items: center;
  height: 2rem;
  padding: 0 var(--cds-spacing-05);
  color: var(--cds-text-02);
  text-decoration: none;
  font-size: var(--cds-body-short-01-font-size);
  white-space: nowrap;
  overflow: hidden;
}

.bx--side-nav__link:hover {
  background-color: var(--cds-hover-ui);
  color: var(--cds-text-01);
}

.bx--side-nav__link--current {
  background-color: var(--cds-selected-ui);
  color: var(--cds-text-01);
  font-weight: 600;
}

.bx--side-nav__icon {
  width: 1rem;
  height: 1rem;
  min-width: 1rem;
  margin-right: var(--cds-spacing-03);
  fill: var(--cds-icon-02);
}

.bx--side-nav__submenu {
  background-color: transparent;
  border: none;
  padding: 0;
  width: 100%;
  text-align: left;
  display: flex;
  align-items: center;
  height: 2rem;
  padding: 0 var(--cds-spacing-05);
  color: var(--cds-text-02);
  font-size: var(--cds-body-short-01-font-size);
  font-weight: 600;
  cursor: pointer;
}

.bx--side-nav__submenu:hover {
  background-color: var(--cds-hover-ui);
}

/* Main content area offset for side nav */
.idp-main-content {
  margin-left: 256px;
  padding: var(--cds-spacing-07);
  transition: margin-left 110ms cubic-bezier(0.2, 0, 1, 0.9);
}

.idp-main-content--nav-collapsed {
  margin-left: 48px;
}

/* Carbon tag styles */
.bx--tag {
  display: inline-flex;
  align-items: center;
  padding: 0 var(--cds-spacing-03);
  height: 1.5rem;
  border-radius: 0.75rem;
  font-size: var(--cds-label-01-font-size);
  font-weight: 400;
}

.bx--tag--blue { background-color: #d0e2ff; color: #0043ce; }
.bx--tag--green { background-color: #defbe6; color: #0e6027; }
.bx--tag--warning { background-color: #fdd13a; color: #3e2400; }
.bx--tag--red { background-color: #ffd7d9; color: #750e13; }
.bx--tag--gray { background-color: var(--cds-ui-03); color: var(--cds-text-02); }

/* Carbon notification inline */
.bx--inline-notification {
  display: flex;
  align-items: flex-start;
  padding: var(--cds-spacing-04) var(--cds-spacing-05);
  border-left: 3px solid;
  margin-bottom: var(--cds-spacing-05);
}

.bx--inline-notification--warning {
  background-color: #fdf6dd;
  border-color: var(--cds-support-03);
}

.bx--inline-notification--error {
  background-color: #fff1f1;
  border-color: var(--cds-support-01);
}

.bx--inline-notification--success {
  background-color: #defbe6;
  border-color: var(--cds-support-02);
}

/* Carbon form elements */
.bx--text-input {
  background-color: var(--cds-field-01);
  border: none;
  border-bottom: 1px solid var(--cds-ui-04);
  color: var(--cds-text-01);
  font-size: var(--cds-body-short-01-font-size);
  height: 2.5rem;
  padding: 0 var(--cds-spacing-04);
  width: 100%;
  border-radius: 0;
  outline: none;
}

.bx--text-input:focus {
  outline: 2px solid var(--cds-focus);
  outline-offset: -2px;
}

/* Carbon grid */
.bx--grid {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 var(--cds-spacing-07);
}

.bx--row {
  display: flex;
  flex-wrap: wrap;
  margin: 0 -var(--cds-spacing-03);
}

/* Responsive breakpoints */
@media (max-width: 672px) {
  .bx--side-nav { width: 0; }
  .idp-main-content { margin-left: 0; }
}
